    for(int i = 0; i < nums.length; i++) {
        if(nums[i] == 13) {
            skipNext = true;
        } else {
            if(!skipNext) {
                sum += nums[i];
            } else {
                skipNext = false;
            }
        }
    }

    return sum;
}

